[
  {
    "name": "Rural Development Index (RDI)",
    "formula": "RDI = (Average Income of Rural Household + Average Literacy Rate + Average Life Expectancy) / 3",
    "variables": {
      "Average Income of Rural Household": "Average income per household in rural areas",
      "Average Literacy Rate": "Average literacy rate in rural areas",
      "Average Life Expectancy": "Average life expectancy of rural population"
    },
    "units": "No specific units, as it's a ratio",
    "notes": "RDI is a composite index used to measure rural development"
  },
