    "name": "Kuznets Curve",
    "formula": "As Income Increases, Inequality Increases, then Decreases",
    "variables": {
      "Income": "Gross national income per capita",
      "Inequality": "Gini coefficient"
    },
    "units": "No specific units, as it's a statement",
    "notes": "Kuznets curve describes the relationship between income and inequality"
  }
]
